Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [ExpectedException(typeof(HttpRequestException))]
    public async Task FetchAsync_Throws_OnFailureStatus()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await fetcher.FetchAsync("https://example.com");
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellation()
    {
        // Handler that delays long enough for cancellation to fire
        var handler = new DelayedHttpMessageHandler(TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // Guard against tests hanging forever
    public async Task FetchAsync_AlreadyCancelledToken_ThrowsImmediately()
    {
        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        var cts = new CancellationTokenSource();
        cts.Cancel(); // Pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }
}
```

And the test helpers:

```csharp
// Returns a canned response immediately
public class MockHttpMessageHandler : HttpMessageHandler
{
    private readonly string _content;
    private readonly HttpStatusCode _statusCode;

    public MockHttpMessageHandler(string content, HttpStatusCode statusCode)
    {
        _content = content;
        _statusCode = statusCode;
    }

    protected override Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        cancellationToken.ThrowIfCancellationRequested();
        var response = new HttpResponseMessage(_statusCode)
        {
            Content = new StringContent(_content)
        };
        return Task.FromResult(response);
    }
}

// Simulates a slow server — respects cancellation
public class DelayedHttpMessageHandler : HttpMessageHandler
{
    private readonly TimeSpan _delay;

    public DelayedHttpMessageHandler(TimeSpan delay) => _delay = delay;

    protected override async Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        await Task.Delay(_delay, cancellationToken); // throws on cancel
        return new HttpResponseMessage(HttpStatusCode.OK);
    }
}
```

**Key takeaways:**

- **`[Timeout(ms)]`** — prevents a broken test from hanging your entire suite
- **`CancellationTokenSource` with a timeout** — tests that your code actually forwards the token through the call chain
- **Pre-cancelled token** — verifies the fast-path cancellation check
- **Custom `HttpMessageHandler`** — avoids mocking frameworks and gives you full control over `HttpClient` behavior; `SendAsync` is the single method all requests flow through
